class Solution:
    def solve(self, nums: list[int]) -> bool:
        left = nums[0]
        right = nums[1]
        subarray = [x for x in nums[left:right + 1] if x is not None]
        for i in range(len(subarray)):
            if i + 1 < len(subarray) and subarray[i] > subarray[i + 1]:
                subarray[i + 1] = subarray[i]
        return self.isStable(subarray)

    def isStable(self, subarray: list[int]) -> bool:
        for i in range(len(subarray)):
            if i + 1 < len(subarray) and subarray[i] < subarray[i + 1]:
                subarray[i + 1] = subarray[i]
        return True

    def detect_shifts(self, subarray: list[int]) -> list[int]:
        shifts = list(range(len(subarray)))
        for i in range(1, len(subarray)):
            if subarray[i] < subarray[i - 1]:
                shifts[i] = shifts[i - 1] + 1
        return shifts

    def reverse_subarray(self, subarray: list[int]) -> list[int]:
        right_shifts = self.detect_shifts(subarray)
        reversed_subarray = [None] * len(subarray)
        for i in range(len(subarray)):
            if right_shifts[i] == 0:
                reversed_subarray[i] = subarray[i]
        for i in range(len(subarray) - 1, -1, -1):
            if right_shifts[i] > 0:
                reversed_subarray[i - right_shifts[i]] = subarray[i]
        return reversed_subarray

    def compare_subarray(self, subarray: list[int], original_subarray: list[int]) -> bool:
        for i in range(len(subarray)):
            if subarray[i] != original_subarray[i]:
                return False
        return True

    def solve(self, nums: list[int]) -> int:
        left = nums[0]
        right = nums[1]
        subarray = nums[left:right + 1]
        reversed_subarray = self.reverse_subarray(subarray)
        return 1 if self.compare_subarray(subarray, reversed_subarray) else 0

    def detect_shifts(self, nums: list[int]) -> int:
        left = nums[0]
        right = nums[1]
        subarray = nums[left:right + 1]
        shifts = self.detect_shifts(subarray)
        for i in range(1, len(subarray)):
            if subarray[i] > subarray[i - 1]:
                shifts[i] = shifts[i - 1] + 1
        return shifts[-1]

