#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    bool solve(vector<int>& nums) {
        int left = nums[0], right = nums[1];
        vector<int> subarray;
        for (int i = left; i <= right; i++)
            subarray.push_back(nums[i]);
        for (int i = 0; i < subarray.size(); i++)
            if (i + 1 < subarray.size() && subarray[i] > subarray[i + 1])
                subarray[i + 1] = subarray[i];
        return isStable(subarray);
    }

    bool isStable(vector<int>& subarray) {
        for (int i = 0; i < subarray.size(); i++)
            if (i + 1 < subarray.size() && subarray[i] > subarray[i + 1])
                return false;
        return true;
    }

    int detect_shifts(vector<int>& nums) {
        int left = nums[0], right = nums[1];
        vector<int> subarray;
        for (int i = left; i <= right; i++)
            subarray.push_back(nums[i]);
        int shifts = 0;
        for (int i = 1; i < subarray.size(); i++)
            if (subarray[i] < subarray[i - 1])
                shifts += 1;
        return shifts;
    }

    vector<int> reverse_subarray(vector<int>& subarray) {
        int shifts = detect_shifts(subarray);
        vector<int> reversed_subarray;
        for (int i = 0; i < subarray.size(); i++)
            if (shifts == 0)
                reversed_subarray.push_back(subarray[i]);
        for (int i = subarray.size() - 1; i >= 0; i--) {
            if (shifts > 0) {
                reversed_subarray.push_back(subarray[i]);
                shifts -= 1;
            }
        }
        return reversed_subarray;
    }

    bool compare_subarray(vector<int>& subarray, vector<int>& original_subarray) {
        for (int i = 0; i < subarray.size(); i++) {
            if (subarray[i] != original_subarray[i])
                return false;
        }
        return true;
    }

    int solve(vector<int>& nums) {
        int left = nums[0], right = nums[1];
        vector<int> subarray = nums[left:right + 1];
        vector<int> reversed_subarray = reverse_subarray(subarray);
        return compare_subarray(subarray, reversed_subarray) ? 1 : 0;
    }
}
